import { useState, useEffect } from 'react';
import { mongoAuthAPI, ordersAPI, addressAPI } from '../api';

/**
 * SESSION STRATEGY
 * ─────────────────────────────────────────────────────────────────────────────
 * Storage layout (per key, written to BOTH storages):
 *
 *   sessionStorage  — tab-scoped, cleared when the tab/browser closes.
 *                     This is the PRIMARY source of truth for auth.
 *   localStorage    — survives tab close; used ONLY as a single-tab
 *                     refresh fallback, protected by a cross-user ID check.
 *
 * Keys stored:
 *   token           — JWT bearer token
 *   user            — serialised user object
 *   serverBootId    — Guid returned by the backend at login time;
 *                     changes on every server restart
 *   currentPage     — last visited page (written by App.js)
 *
 * Rehydration on mount:
 *   1. Read token + user from sessionStorage (priority) or localStorage.
 *   2. Call GET /api/mongo/auth/validate.
 *        • Network error / non-2xx  → server down        → clear → home
 *        • bootId in response ≠ stored bootId            → restarted → clear → home
 *        • bootId matches (or backend doesn't send one)  → session valid → restore user
 *   3. currentPage is preserved so refresh stays on the correct page.
 *
 * Login:
 *   Write token + user + serverBootId to both storages.
 *
 * Logout:
 *   Wipe all keys from both storages.
 * ─────────────────────────────────────────────────────────────────────────────
 */

// ── Keys managed by this module ──────────────────────────────────────────────
const SESSION_KEYS = ['token', 'user', 'serverBootId'];
// NOTE: 'currentPage' is intentionally NOT in this list — App.js owns it and
// we must NOT clear it on logout so the user lands on 'home' via routing logic,
// not because the key disappeared mid-render.

// ── Storage helpers ──────────────────────────────────────────────────────────

const writeTabSession = (token, userData, bootId) => {
  sessionStorage.setItem('token',        token);
  sessionStorage.setItem('user',         JSON.stringify(userData));
  if (bootId) sessionStorage.setItem('serverBootId', bootId);
};

const writeLocalHint = (token, userData, bootId) => {
  localStorage.setItem('token',        token);
  localStorage.setItem('user',         JSON.stringify(userData));
  if (bootId) localStorage.setItem('serverBootId', bootId);
};

/** Wipe auth keys from both storages. Does NOT touch 'currentPage'. */
const clearAuthSession = () => {
  SESSION_KEYS.forEach(k => {
    sessionStorage.removeItem(k);
    localStorage.removeItem(k);
  });
  // Also clear cart on logout
  sessionStorage.removeItem('cart');
  localStorage.removeItem('cart');
};

// ── JWT helpers ──────────────────────────────────────────────────────────────

const extractUserIdFromToken = (token) => {
  try {
    if (!token) return null;
    const payload = JSON.parse(atob(token.split('.')[1]));
    return (
      payload.nameid ||
      payload['http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier'] ||
      payload.sub  ||
      payload.userId ||
      null
    );
  } catch {
    return null;
  }
};

// ── Tab-session resolver ─────────────────────────────────────────────────────

const resolveTabSession = () => {
  // Priority 1: sessionStorage (this tab's own isolated session)
  const ssToken = sessionStorage.getItem('token');
  const ssUser  = sessionStorage.getItem('user');
  if (ssToken && ssUser) {
    try {
      return { token: ssToken, userData: JSON.parse(ssUser), source: 'session' };
    } catch {
      sessionStorage.removeItem('token');
      sessionStorage.removeItem('user');
    }
  }

  // Priority 2: localStorage — only accepted if user ID in token matches stored user
  const lsToken = localStorage.getItem('token');
  const lsUser  = localStorage.getItem('user');
  if (!lsToken || !lsUser) return null;

  try {
    const userData    = JSON.parse(lsUser);
    const tokenUserId = extractUserIdFromToken(lsToken);
    const storedId    = String(userData.userId || userData.id || '');

    if (tokenUserId && storedId && String(tokenUserId) !== storedId) {
      console.warn('⚠️ Cross-tab contamination blocked: token owner ≠ stored user');
      return null;
    }
    return { token: lsToken, userData, source: 'local' };
  } catch {
    return null;
  }
};

// ── Server validation + restart detection ────────────────────────────────────

/**
 * Call the validate endpoint.
 * Returns { ok: boolean, bootId: string | null }
 *
 * The backend (MongoAuthController) now returns:
 *   { valid: true, bootId: "<Guid>" }
 * and also sets the header X-Server-Boot-Id for belt-and-suspenders.
 *
 * If the call fails for any reason (network down, 401, 500) ok = false.
 */
const callValidate = async (token) => {
  try {
    const response = await fetch('/api/mongo/auth/validate', {
      method: 'GET',
      headers: {
        Authorization:  `Bearer ${token}`,
        'Content-Type': 'application/json'
      }
    });

    if (!response.ok) {
      return { ok: false, bootId: null };
    }

    // Read boot ID from JSON body (primary) or header (fallback)
    let bootId = null;
    try {
      const json = await response.json();
      bootId = json?.bootId || response.headers.get('X-Server-Boot-Id') || null;
    } catch {
      bootId = response.headers.get('X-Server-Boot-Id') || null;
    }

    return { ok: true, bootId };
  } catch (err) {
    console.warn('⚠️ validate unreachable:', err.message);
    return { ok: false, bootId: null };
  }
};

// ── Hook ─────────────────────────────────────────────────────────────────────

export const useAuth = () => {
  const [user,        setUser]        = useState(null);
  const [orders,      setOrders]      = useState([]);
  const [profileData, setProfileData] = useState({
    fullName: '', email: '', mobile: '', gender: '', addresses: []
  });
  const [isInitializing, setIsInitializing] = useState(true);

  // ── Rehydration ────────────────────────────────────────────────────────
  useEffect(() => {
    const restoreSession = async () => {
      try {
        const resolved = resolveTabSession();

        if (!resolved) {
          console.log('ℹ️ No stored session — home page');
          return;
        }

        const { token, userData, source } = resolved;

        // ── Step 1: Server liveness + boot-ID check ──────────────────────
        console.log('🔍 Validating session with server...');
        const { ok, bootId: currentBootId } = await callValidate(token);

        if (!ok) {
          // Server down or token hard-rejected
          console.warn('⚠️ Server rejected token / unreachable — clearing auth, going home');
          clearAuthSession();
          // Reset currentPage to home so App.js routes correctly
          sessionStorage.setItem('currentPage', 'home');
          localStorage.setItem('currentPage',   'home');
          return;
        }

        // ── Step 2: Boot-ID comparison (server-restart detection) ─────────
        if (currentBootId) {
          const storedBootId =
            sessionStorage.getItem('serverBootId') ||
            localStorage.getItem('serverBootId');

          if (storedBootId && storedBootId !== currentBootId) {
            // Boot ID changed → server restarted since last login
            console.warn(
              `⚠️ Server restarted detected! ` +
              `Stored boot ID: ${storedBootId} | Current: ${currentBootId} — clearing session`
            );
            clearAuthSession();
            sessionStorage.setItem('currentPage', 'home');
            localStorage.setItem('currentPage',   'home');
            return;
          }

          // Update stored boot ID (e.g. first load after login via localStorage)
          if (!storedBootId) {
            sessionStorage.setItem('serverBootId', currentBootId);
            localStorage.setItem('serverBootId',   currentBootId);
          }
        }

        // ── Step 3: Restore user ─────────────────────────────────────────
        const tokenUserId = extractUserIdFromToken(token);
        const finalUserId = tokenUserId || userData.userId || userData.id;

        if (!finalUserId) {
          console.warn('⚠️ Cannot resolve user ID — clearing session');
          clearAuthSession();
          sessionStorage.setItem('currentPage', 'home');
          localStorage.setItem('currentPage',   'home');
          return;
        }

        const rehydratedUser = { ...userData, id: finalUserId, userId: finalUserId };

        // Promote localStorage session into sessionStorage for tab isolation
        if (source === 'local') {
          const bootId = localStorage.getItem('serverBootId');
          writeTabSession(token, rehydratedUser, bootId);
          console.log('📋 Promoted localStorage → sessionStorage');
        }

        setUser(rehydratedUser);
        console.log(`✅ Session restored from ${source}Storage for: ${rehydratedUser.email}`);

      } catch (err) {
        console.error('❌ Session restore failed:', err);
        clearAuthSession();
        sessionStorage.setItem('currentPage', 'home');
        localStorage.setItem('currentPage',   'home');
      } finally {
        setIsInitializing(false);
      }
    };

    restoreSession();
  }, []);

  // ── Login ──────────────────────────────────────────────────────────────
  const handleLogin = async (loginData, loginRole, setError, setLoading) => {
    setError('');
    setLoading(true);

    try {
      if (!loginData.email?.trim()) throw new Error('Email is required');
      if (!loginData.password)       throw new Error('Password is required');

      console.log('🔐 Attempting login...');

      const response = await mongoAuthAPI.login(
        loginData.email.trim(),
        loginData.password
      );

      const data = response?.data;
      if (!data?.token) throw new Error('Authentication token not received from server');

      const userRole = String(data.role || '').trim();
      if (!userRole || (userRole !== 'Customer' && userRole !== 'Admin')) {
        throw new Error('Invalid user role received from server');
      }
      if (userRole !== loginRole) {
        throw new Error(
          `This account is registered as ${userRole}. Please select ${userRole} login.`
        );
      }

      const tokenUserId = extractUserIdFromToken(data.token);
      const finalUserId = tokenUserId || data.mongoUserId || data.userId || data.id;
      if (!finalUserId) throw new Error('User ID not found. Please contact support.');

      const userData = {
        ...data,
        role: userRole,
        userId: finalUserId,
        id: finalUserId,
        email: data.email
      };

      // ── Fetch the server's current boot ID and store it ────────────────
      // We call validate immediately after login so we have the boot ID
      // before the user navigates anywhere. This is what we compare on
      // every subsequent rehydration to detect server restarts.
      let bootId = null;
      try {
        const { ok, bootId: bid } = await callValidate(data.token);
        if (ok && bid) bootId = bid;
      } catch {
        // Non-fatal — restart detection just won't work for this session
        console.warn('⚠️ Could not fetch boot ID at login time');
      }

      writeTabSession(data.token, userData, bootId);
      writeLocalHint(data.token, userData, bootId);

      const userState = {
        id: finalUserId,
        userId: finalUserId,
        email:  data.email  || '',
        role:   userRole,
        name:   data.fullName || data.name || '',
        mobile: data.mobile || '',
        gender: data.gender || ''
      };

      setUser(userState);
      console.log('✅ Login successful, boot ID stored:', bootId);
      return userRole;

    } catch (err) {
      console.error('❌ Login error:', err);
      throw err;
    } finally {
      setLoading(false);
    }
  };

  // ── Register ───────────────────────────────────────────────────────────
  const handleRegister = async (registerData, loginRole, setError, setLoading) => {
    const { fullName, email, mobile, password, confirmPassword, gender } = registerData;

    if (!fullName?.trim())            throw new Error('Full name is required');
    if (!email?.trim())               throw new Error('Email is required');
    if (!mobile?.trim())              throw new Error('Mobile number is required');
    if (!password)                    throw new Error('Password is required');
    if (password !== confirmPassword) throw new Error('Passwords do not match');
    if (password.length < 6)         throw new Error('Password must be at least 6 characters');

    setLoading(true);
    setError('');

    try {
      console.log('📝 Attempting registration...');

      const response = await mongoAuthAPI.register(
        fullName.trim(), email.trim(), mobile.trim(), password, gender
      );

      const data = response.data;
      if (!data.token) throw new Error('No token received from server');
      if (!data.role)  throw new Error('No role returned from server');

      const tokenUserId = extractUserIdFromToken(data.token);
      const finalUserId = tokenUserId || data.userId || data.id || data.mongoUserId;
      if (!finalUserId) throw new Error('User ID not found in token.');

      const userData = { ...data, userId: finalUserId, id: finalUserId };

      let bootId = null;
      try {
        const { ok, bootId: bid } = await callValidate(data.token);
        if (ok && bid) bootId = bid;
      } catch { /* non-fatal */ }

      writeTabSession(data.token, userData, bootId);
      writeLocalHint(data.token, userData, bootId);

      setUser({
        id: finalUserId, userId: finalUserId,
        email:  data.email,  role:   data.role,
        name:   data.fullName, mobile: data.mobile || mobile,
        gender: data.gender || gender
      });

      setProfileData({
        fullName: data.fullName || fullName,
        email:    data.email    || email,
        mobile:   data.mobile   || mobile,
        gender:   data.gender   || gender,
        addresses: []
      });

      console.log('✅ Registration successful');
      return true;

    } catch (err) {
      console.error('❌ Registration error:', err);
      throw err;
    } finally {
      setLoading(false);
    }
  };

  // ── Logout ─────────────────────────────────────────────────────────────
  const handleLogout = () => {
    clearAuthSession();
    // Explicitly set page to home so App.js routes to HomePage after clearing user
    sessionStorage.setItem('currentPage', 'home');
    localStorage.setItem('currentPage',   'home');

    setUser(null);
    setOrders([]);
    setProfileData({ fullName: '', email: '', mobile: '', gender: '', addresses: [] });
    console.log('✅ Logged out');
  };

  // ── Profile ────────────────────────────────────────────────────────────
  const loadProfile = async () => {
    if (!user) return;
    try {
      let addresses = [];
      try {
        if (typeof addressAPI?.getAll === 'function') {
          const addrRes = await addressAPI.getAll();
          addresses = Array.isArray(addrRes?.data)
            ? addrRes.data
            : addrRes?.data?.addresses || [];
        }
      } catch (err) {
        console.warn('⚠️ Could not fetch addresses:', err);
      }

      addresses = (addresses || []).map((a, index) => {
        const mongoId = a._id || a.id || a.Id || `addr_${index}`;
        return {
          id: mongoId, _id: mongoId,
          label:        a.label || a.Label || (a.IsDefault ? 'Home' : 'Address'),
          AddressLine1: a.AddressLine1 || a.addressLine1 || '',
          AddressLine2: a.AddressLine2 || a.addressLine2 || '',
          City:         a.City  || a.city  || '',
          State:        a.State || a.state || '',
          PostalCode:   a.PostalCode || a.postalCode || '',
          Country:      a.Country   || a.country    || 'India',
          IsDefault:    Boolean(a.IsDefault || a.isDefault)
        };
      });

      setProfileData(prev => ({ ...prev, addresses }));
    } catch (err) {
      console.error('❌ Error loading profile:', err);
      setProfileData(prev => ({ ...prev, addresses: [] }));
    }
  };

  // ── Orders ─────────────────────────────────────────────────────────────
  const loadOrders = async () => {
    if (!user) return;
    try {
      const response  = await ordersAPI.history();
      const ordersData = response?.data || [];
      setOrders(ordersData);
    } catch (err) {
      console.error('❌ Error loading orders:', err);
      setOrders([]);
    }
  };

  return {
    user, setUser,
    orders, setOrders,
    profileData, setProfileData,
    isInitializing,
    handleLogin, handleRegister, handleLogout,
    loadProfile, loadOrders
  };
};
